import { FormsPrevalueSourceCollectionServerDataSource } from './prevaluesource-collection.server.data-source.js';
import type { FormsPrevalueSourceCollectionDataSource, FormsPrevalueSourceCollectionFilterModel } from './types.js';
import type { UmbCollectionRepository } from '@umbraco-cms/backoffice/collection';
import type { UmbControllerHost } from '@umbraco-cms/backoffice/controller-api';

export class FormsPrevalueSourceCollectionRepository implements UmbCollectionRepository {
	#collectionSource: FormsPrevalueSourceCollectionDataSource;

	constructor(host: UmbControllerHost) {
		this.#collectionSource = new FormsPrevalueSourceCollectionServerDataSource(host);
	}

	async requestCollection(filter: FormsPrevalueSourceCollectionFilterModel) {
		return this.#collectionSource.getCollection(filter);
	}

	destroy(): void {}
}

export default FormsPrevalueSourceCollectionRepository;
