import type { UmbCollectionDataSource } from '@umbraco-cms/backoffice/collection';
import type { UmbControllerHost } from '@umbraco-cms/backoffice/controller-api';
import { tryExecuteAndNotify } from '@umbraco-cms/backoffice/resources';
import type { FieldPreValueSource } from '@umbraco-forms/generated';
import { PrevalueSourceService } from '@umbraco-forms/generated';
import type { FormsPrevalueSourceCollectionFilterModel } from './types.js';

export class FormsPrevalueSourceCollectionServerDataSource implements UmbCollectionDataSource<FieldPreValueSource> {
	#host: UmbControllerHost;

	constructor(host: UmbControllerHost) {
		this.#host = host;
	}

	async getCollection(filter: FormsPrevalueSourceCollectionFilterModel) {
		const { data, error } = await tryExecuteAndNotify(this.#host, PrevalueSourceService.getPrevalueSource(filter));

		if (data) {
			return { data };
		}

		return { error };
	}
}
